const now = Math.floor(Date.now() / 1000);

function rand(min, max, fixed = 2) {
    return +(Math.random() * (max - min) + min).toFixed(fixed);
}
function randInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

function phase() {
    const voltage = rand(228, 232, 1);
    const current = rand(0.02, 0.5, 3);
    const act = +(voltage * current * rand(0.6, 0.9)).toFixed(1);
    const aprt = +(voltage * current).toFixed(1);
    return {
        current,
        voltage,
        act_power: act,
        aprt_power: aprt,
        pf: +(act / aprt).toFixed(2),
        freq: 50.0
    };
}

const a = phase();
const b = phase();
const c = phase();

